class Solution {
    public int[] earliestAndLatest(int n, int firstPlayer, int secondPlayer) {
        int earliest = 1, latest = 1;
        for (int i = 2; i <= n; i <<= 1) {
            int mid = i >> 1;
            if (firstPlayer <= mid && secondPlayer > mid) {
                earliest = Math.max(earliest, (firstPlayer + mid - 1) / mid);
                latest = Math.min(latest, (secondPlayer - 1) / mid + 1);
            } else if (firstPlayer > mid && secondPlayer <= i) {
                earliest = Math.max(earliest, (secondPlayer + mid) / mid);
                latest = Math.min(latest, (firstPlayer - 1) / mid + 1);
            } else {
                earliest = Math.max(earliest, (firstPlayer + secondPlayer - i) / mid + 1);
                latest = Math.min(latest, (firstPlayer + secondPlayer - 1) / mid + 1);
            }
        }
        return new int[] {earliest, latest};
    }
}
